class Solution(object):
    def findIndices(self, nums, indexDifference, valueDifference):
        n = len(nums)
        min_idx = max_idx = 0  # indices of min and max in sliding window [0..j]
        for j in range(indexDifference, n):
            i = j - indexDifference  # i is available
            # Update min and max trackers
            if nums[i] < nums[min_idx]:
                min_idx = i
            if nums[i] > nums[max_idx]:
                max_idx = i
            # Check max vs nums[j]
            if abs(nums[max_idx] - nums[j]) >= valueDifference:
                return [max_idx, j]
            # Check min vs nums[j]
            if abs(nums[min_idx] - nums[j]) >= valueDifference:
                return [min_idx, j]
        return [-1, -1]
